1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	
21	const groupByType = (items: Item[]): Item[][] => {
22	  const groups = new Map<string, Item[]>();
23	  for (const item of items) {
24	    const group = groups.get(item.type) ?? [];
25	    group.push(item);
26	    groups.set(item.type, group);
27	  }
28	  return [...groups.values()];
29	};
30	
31	const formsAComponentBlock = (group: Item[]): boolean =>
32	  group.length === COMPONENT_BLOCK_SIZE;
33	
34	const sumOfBasePremiums = (items: Item[]): number =>
35	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
36	
37	const basePremiumForGroup = (group: Item[]): number =>
38	  formsAComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
39	
40	const totalBasePremium = (items: Item[]): number =>
41	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
42	
43	const premiumFor = (items: Item[]): number =>
44	  totalBasePremium(items) + PROCESSING_FEE;
45	
46	const resultFor = (step: QuoteStep) => ({ premium: premiumFor(step.items) });
47	
48	export const runScenario = (input: unknown): unknown => {
49	  const scenario = input as Scenario;
50	  return { results: scenario.steps.map(resultFor) };
51	};
